import '../constants/api_endpoints.dart';import '../models/models.dart';import 'api_service.dart';
class GamificationService{GamificationService(this._api);final ApiService _api;Future<dynamic> dailyQuestConfig()=>_api.get(ApiEndpoints.dailyQuestsConfig);Future<dynamic> badgesConfig()=>_api.get(ApiEndpoints.badgesConfig);Future<List<AchievementModel>> achievements()async{final r=await _api.get(ApiEndpoints.achievements,query:{'depth':2});return ((r as List?)??[]).map((e)=>AchievementModel.fromJson(e)).toList();}Future<List<QuestStatus>> profileDailyQuest()async{final r=await _api.get(ApiEndpoints.profileDailyQuest);return ((r is Map?r['challengeStatuses']:null) as List? ??[]).map((e)=>QuestStatus.fromJson(e)).toList();}Future<dynamic> palmRefill()=>_api.get(ApiEndpoints.palmRefill);Future<StreakModel> learnerStreak()async=>StreakModel.fromJson(await _api.get(ApiEndpoints.learnerStreak));Future<dynamic> restoreStreak(int days)=>_api.get(ApiEndpoints.restoreStreak(days));Future<GamificationStock> stocks()async=>GamificationStock.fromJson(await _api.get(ApiEndpoints.gamificationStocks));}
